import{_ as a,o as i,c as t,S as l}from"./chunks/framework.DZlzLDBr.js";const g=JSON.parse('{"title":"Reading View Styles","description":"","frontmatter":{},"headers":[],"relativePath":"Reading-View-Styles.md","filePath":"Reading-View-Styles.md","lastUpdated":null}'),r={name:"Reading-View-Styles.md"};function s(n,e,o,d,c,u){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="reading-view-styles" tabindex="-1">Reading View Styles <a class="header-anchor" href="#reading-view-styles" aria-label="Permalink to &quot;Reading View Styles&quot;">​</a></h1><p>Last modified: 16/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This page explains the Reading View macro styles in Sprout.</p><p>Use <strong>Settings → Reading → Macro styles</strong> to switch between them.</p><h2 id="card-styles" tabindex="-1">Card Styles <a class="header-anchor" href="#card-styles" aria-label="Permalink to &quot;Card Styles&quot;">​</a></h2><p>Currently available:</p><ul><li><strong>Disabled</strong>: turns off Sprout card styling and uses native Obsidian reading rendering.</li><li><strong>Flashcards</strong>: fastest active-recall view with flip interaction (question face ↔ answer face).</li><li><strong>Clean markdown</strong>: minimal note-like rendering with low chrome and clean text flow.</li></ul><p>Planned for a future update:</p><ul><li><strong>Classic</strong>: structured card sections with progressive reveal.</li><li><strong>Guidebook</strong>: walkthrough / step-by-step reading layout.</li><li><strong>Custom</strong>: user-defined CSS styling with dedicated hook classes.</li></ul><h3 id="flashcards" tabindex="-1">Flashcards <a class="header-anchor" href="#flashcards" aria-label="Permalink to &quot;Flashcards&quot;">​</a></h3><ul><li>Purpose: fastest active-recall view.</li><li>Behavior: flip interaction (question face ↔ answer face).</li><li>Best for: quick recall blocks.</li><li>Typical layout: masonry.</li></ul><h3 id="clean-markdown" tabindex="-1">Clean markdown <a class="header-anchor" href="#clean-markdown" aria-label="Permalink to &quot;Clean markdown&quot;">​</a></h3><ul><li>Purpose: minimal note-like rendering.</li><li>Behavior: low chrome, clean text flow.</li><li>Best for: reading-heavy material and concise review.</li><li>Typical layout: vertical.</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><ul><li><strong>Reading view fields</strong> are configured and saved per style.</li><li><strong>Reading view colours</strong> are also per style (except Flashcards).</li><li>This keeps each style standalone, so changes on one style do not affect others.</li></ul><h2 id="next-step" tabindex="-1">Next step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next step&quot;">​</a></h2><p>Classic, Guidebook, and Custom are planned for a future release. See <a href="./Custom-Reading-Styles">Custom Reading Styles</a> for Custom plans.</p>',18)])])}const p=a(r,[["render",s]]);export{g as __pageData,p as default};
